36	/// Sub-assertion within a case: run bash snippet, check exit code.
37	struct RbtdrfSub {
38	    label: &'static str,
39	    setup: &'static str,
40	    command: &'static str,
41	    expect_ok: bool,
42	}
43	
44	impl RbtdrfSub {
45	    const fn ok(label: &'static str, setup: &'static str) -> Self {
46	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: true }
47	    }
48	    const fn fatal(label: &'static str, setup: &'static str) -> Self {
49	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: false }
50	    }
51	    const fn ok_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
52	        Self { label, setup, command, expect_ok: true }
53	    }
54	    const fn fatal_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
55	        Self { label, setup, command, expect_ok: false }
56	    }
