59	/// Run a bash script, return (exit_code, stdout, stderr). Saves traces to case dir.
60	fn rbtdrf_run_bash(
61	    project_root: &Path,
62	    script: &str,
63	    dir: &Path,
64	    trace_prefix: &str,
65	) -> Result<(i32, String, String), String> {
66	    let output = Command::new("bash")
67	        .arg("-c")
68	        .arg(script)
69	        .current_dir(project_root)
70	        .output()
71	        .map_err(|e| format!("bash execution failed: {}", e))?;
72	
73	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
74	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
75	    let code = output.status.code().unwrap_or(-1);
76	
77	    let _ = std::fs::write(dir.join(format!("{}-script.sh", trace_prefix)), script);
78	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", trace_prefix)), &stdout);
79	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", trace_prefix)), &stderr);
80	
81	    Ok((code, stdout, stderr))
82	}
