84	/// Run enrollment-validation sub-assertions against BUV.
85	fn rbtdrf_run_ev(
86	    dir: &Path,
87	    enrollment: &str,
88	    subs: &[RbtdrfSub],
89	) -> rbtdre_Verdict {
90	    let root = match std::env::current_dir() {
91	        Ok(r) => r,
92	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
93	    };
94	    let buv = root.join("Tools/buk/buv_validation.sh");
95	
96	    for (i, sub) in subs.iter().enumerate() {
97	        let script = format!(
98	            "set -euo pipefail\nsource '{}'\nzbuv_kindle\nzbuv_reset_enrollment\n{}\n{}\n{}",
99	            buv.display(),
100	            enrollment,
101	            sub.setup,
102	            sub.command,
103	        );
104	
105	        match rbtdrf_run_bash(&root, &script, dir, &format!("sub-{}", i)) {
106	            Ok((code, _, _)) => {
107	                let ok = code == 0;
108	                if ok != sub.expect_ok {
109	                    return if sub.expect_ok {
110	                        rbtdre_Verdict::Fail(format!("{}: expected ok, got exit {}", sub.label, code))
111	                    } else {
112	                        rbtdre_Verdict::Fail(format!("{}: expected failure, got exit 0", sub.label))
113	                    };
114	                }
115	            }
116	            Err(e) => {
117	                return rbtdre_Verdict::Fail(format!("{}: {}", sub.label, e));
118	            }
119	        }
120	    }
121	    rbtdre_Verdict::Pass
122	}
